fun solve(nums: Array<Long>): Long {
    val sorted = nums.map { it.abs() }.sorted()
    var count = 0L
    for (i in 0 until sorted.size - 1) {
        val target = 2 * sorted[i]
        var low = i + 1
        var high = sorted.size - 1
        var res = -1
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted[mid] <= target) {
                res = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        if (res != -1) {
            count += res - i
        }
    }
    return count
}
